import{_ as a,o as e,c as r,a2 as o}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"回合制系统","description":"","frontmatter":{},"headers":[],"relativePath":"guide/turn-based.md","filePath":"guide/turn-based.md","lastUpdated":1781112327000}'),d={name:"guide/turn-based.md"};function n(s,t,i,l,h,u){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="回合制系统" tabindex="-1">回合制系统 <a class="header-anchor" href="#回合制系统" aria-label="Permalink to &quot;回合制系统&quot;">​</a></h1><p>FunGame 采用<strong>完全回合制</strong>，角色按顺序行动，只有先前角色行动结束后，才轮到下一个角色。</p><h2 id="round-与-turn" tabindex="-1">Round 与 Turn <a class="header-anchor" href="#round-与-turn" aria-label="Permalink to &quot;Round 与 Turn&quot;">​</a></h2><p>回合分为 <code>Round</code> 和 <code>Turn</code> 两种表示：</p><table tabindex="0"><thead><tr><th>概念</th><th>含义</th></tr></thead><tbody><tr><td><strong>Round</strong></td><td>游戏回合。每个角色的一次行动，都是一个 Round</td></tr><tr><td><strong>Turn</strong></td><td>角色轮次。角色每次轮到行动，即为该角色的一个 Turn</td></tr></tbody></table><blockquote><p>⚠️ <strong>关键区分</strong>：技能特效计算的回合数，以角色的 Turn 为准。由于顺序表存在插队机制，每个角色的 Turn 数是不同的。</p></blockquote><h2 id="回合外" tabindex="-1">回合外 <a class="header-anchor" href="#回合外" aria-label="Permalink to &quot;回合外&quot;">​</a></h2><p>任意角色的回合，对于其他角色而言都是<strong>回合外</strong>。</p><p>本质上行动顺序是一个环形：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>回合外 → 回合开始 → 行动阶段 → 回合结束 → 回合外</span></span></code></pre></div><h2 id="回合内" tabindex="-1">回合内 <a class="header-anchor" href="#回合内" aria-label="Permalink to &quot;回合内&quot;">​</a></h2><p>回合内分为以下几个阶段：</p><h3 id="准备阶段" tabindex="-1">准备阶段 <a class="header-anchor" href="#准备阶段" aria-label="Permalink to &quot;准备阶段&quot;">​</a></h3><p>准备阶段会检查角色的状态：</p><ul><li>角色处于 <strong>控制态</strong> → 行动决策受影响，甚至可能跳过回合</li><li>角色处于 <strong>吟唱态</strong> → 结算吟唱的技能，决策受限</li></ul><h3 id="行动阶段" tabindex="-1">行动阶段 <a class="header-anchor" href="#行动阶段" aria-label="Permalink to &quot;行动阶段&quot;">​</a></h3><p>处于 <strong>常态</strong> 的角色可以进行决策：</p><table tabindex="0"><thead><tr><th>行动</th><th>说明</th></tr></thead><tbody><tr><td>普通攻击</td><td>基于攻击力的物理伤害</td></tr><tr><td>释放战技</td><td>消耗爆发能量</td></tr><tr><td>吟唱魔法</td><td>使角色进入吟唱态（结束回合）</td></tr><tr><td>使用物品</td><td>消耗品/装备</td></tr><tr><td>放弃行动</td><td>本轮不操作</td></tr></tbody></table><h3 id="结束阶段" tabindex="-1">结束阶段 <a class="header-anchor" href="#结束阶段" aria-label="Permalink to &quot;结束阶段&quot;">​</a></h3><p>此阶段进行各种结算：硬直时间计算、时间流逝、状态持续时间更新等。</p><h2 id="时间" tabindex="-1">时间 <a class="header-anchor" href="#时间" aria-label="Permalink to &quot;时间&quot;">​</a></h2><p>回合制同样存在<strong>时间 (Time)</strong>。</p><h3 id="硬直时间-hardness-time" tabindex="-1">硬直时间 (Hardness Time) <a class="header-anchor" href="#硬直时间-hardness-time" aria-label="Permalink to &quot;硬直时间 (Hardness Time)&quot;">​</a></h3><p>也称行动延迟 (Action Delay)：<strong>角色无法行动的时间，或下次行动所需的等待时间</strong>。</p><ul><li>没有角色行动时 → 时间持续流逝，直到有角色硬直时间衰减至零</li><li>角色行动回合内 → 时间暂停</li><li>每当时间流逝 → 减少硬直时间、冷却时间、特效持续时间</li></ul><blockquote><p>时间没有确切单位，可用&quot;秒&quot;或&quot;单位时间&quot;泛指。每次计算保留两位小数。</p></blockquote>',26)])])}const b=a(d,[["render",n]]);export{p as __pageData,b as default};
